import {
  AuthProvider as AuthProviderPrimitive,
  type AuthProviderProps
} from "@better-auth-ui/solid"

import { ErrorToaster } from "./error-toaster"

export type { AuthProviderProps }

const resolveProviderChildren = (children: AuthProviderProps["children"]) =>
  typeof children === "function" ? children() : children

export function AuthProvider(props: AuthProviderProps) {
  const { children, ...config } = props

  return (
    <AuthProviderPrimitive {...config}>
      {() => (
        <>
          {resolveProviderChildren(children)}
          <ErrorToaster />
        </>
      )}
    </AuthProviderPrimitive>
  )
}

import { useQueryClient } from "@tanstack/solid-query"
import type { BetterFetchError } from "better-auth/client"
import { onMount } from "solid-js"
import { toast } from "solid-sonner"

const resolveErrorMessage = (error: Error) =>
  (error as BetterFetchError)?.error?.message || error.message

export function ErrorToaster() {
  const queryClient = useQueryClient()

  onMount(() => {
    queryClient.getQueryCache().config.onError = (error) => {
      const err = error as BetterFetchError
      if (err?.error) toast.error(err.error.message)
    }

    queryClient.setMutationDefaults([], {
      onError: (error) => {
        toast.error(resolveErrorMessage(error))
      }
    })
  })

  return null
}

import {
  CircleCheck,
  Info,
  LoaderCircle,
  OctagonX,
  TriangleAlert
} from "lucide-solid"
import {
  type ComponentProps,
  createSignal,
  type JSX,
  onCleanup,
  onMount
} from "solid-js"
import { Toaster as Sonner } from "solid-sonner"

import { readStoredThemePreference, resolveThemePreference } from "@/lib/theme"

type ToasterProps = ComponentProps<typeof Sonner>

const resolveCurrentTheme = (): ToasterProps["theme"] => {
  const prefersDark = matchMedia("(prefers-color-scheme: dark)").matches

  return resolveThemePreference(readStoredThemePreference(), prefersDark)
}

const Toaster = (props: ToasterProps) => {
  const [theme, setTheme] = createSignal<ToasterProps["theme"]>("system")

  onMount(() => {
    const mediaQuery = matchMedia("(prefers-color-scheme: dark)")
    const syncTheme = () => setTheme(resolveCurrentTheme())

    syncTheme()
    window.addEventListener("storage", syncTheme)
    mediaQuery.addEventListener("change", syncTheme)

    onCleanup(() => {
      window.removeEventListener("storage", syncTheme)
      mediaQuery.removeEventListener("change", syncTheme)
    })
  })

  return (
    <Sonner
      theme={theme()}
      class="toaster group"
      position="top-center"
      icons={{
        success: <CircleCheck class="size-4" />,
        info: <Info class="size-4" />,
        warning: <TriangleAlert class="size-4" />,
        error: <OctagonX class="size-4" />,
        loading: <LoaderCircle class="size-4 animate-spin" />
      }}
      style={
        {
          "--normal-bg": "var(--popover)",
          "--normal-text": "var(--popover-foreground)",
          "--normal-border": "var(--border)",
          "--border-radius": "var(--radius)"
        } as JSX.CSSProperties
      }
      {...props}
    />
  )
}

export { Toaster }

export type ThemeMode = "system" | "light" | "dark"

export const themeStorageKey = "start-solid-zaidan-theme"

export const isThemeMode = (value: string | null): value is ThemeMode =>
  value === "system" || value === "light" || value === "dark"

export const resolveThemePreference = (
  theme: ThemeMode,
  prefersDark: boolean
): "light" | "dark" =>
  theme === "system" ? (prefersDark ? "dark" : "light") : theme

export const setDocumentThemeClass = (theme: "light" | "dark") => {
  document.documentElement.classList.remove("light", "dark")
  document.documentElement.classList.add(theme)
}

export const readStoredThemePreference = (): ThemeMode => {
  const storedTheme = localStorage.getItem(themeStorageKey)

  return isThemeMode(storedTheme) ? storedTheme : "system"
}

export const saveThemePreference = (theme: ThemeMode) => {
  localStorage.setItem(themeStorageKey, theme)
}

export const applyThemePreference = (theme: ThemeMode) => {
  const prefersDark = matchMedia("(prefers-color-scheme: dark)").matches

  setDocumentThemeClass(resolveThemePreference(theme, prefersDark))
}

export const syncDocumentThemePreference = () => {
  const mediaQuery = matchMedia("(prefers-color-scheme: dark)")
  const applyStoredPreference = () => {
    applyThemePreference(readStoredThemePreference())
  }
  const handleSystemThemeChange = () => {
    if (readStoredThemePreference() === "system") applyStoredPreference()
  }
  const handleStorage = (event: StorageEvent) => {
    if (event.key === themeStorageKey) applyStoredPreference()
  }

  applyStoredPreference()
  window.addEventListener("storage", handleStorage)
  mediaQuery.addEventListener("change", handleSystemThemeChange)

  return () => {
    window.removeEventListener("storage", handleStorage)
    mediaQuery.removeEventListener("change", handleSystemThemeChange)
  }
}

export const themeScript = `
try {
  const themeStorageKey = "${themeStorageKey}";
  const storedTheme = localStorage.getItem(themeStorageKey);
  const theme = storedTheme === "light" || storedTheme === "dark" || storedTheme === "system" ? storedTheme : "system";
  const prefersDark = matchMedia("(prefers-color-scheme: dark)").matches;
  const resolvedTheme = theme === "system" ? (prefersDark ? "dark" : "light") : theme;
  document.documentElement.classList.remove("light", "dark");
  document.documentElement.classList.add(resolvedTheme);
} catch (_) {}
`
